            --bg-color: #0B132B;
            --text-main: #FFFFFF;
            --text-muted: #8A9AAB;
            --accent-cyan: #00E5FF;
            --accent-coral: #FF3366;
            --panel-bg: rgba(255, 255, 255, 0.05);
        }

        * { box-sizing: border-box; margin: 0; padding: 0; }

        body {
            font-family: 'Inter', sans-serif;
            background-color: var(--bg-color);
            color: var(--text-main);
            overflow: hidden; /* Prevent scrolling */
            display: flex;
            justify-content: center;
            align-items: center;
            height: 100vh;
        }

        /* Deck Container */
        #deck {
            position: relative;
            width: 100vw;
            height: 100vh;
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
        }

        /* Slides */
        .slide {
            position: absolute;
            top: 0; left: 0;
            width: 100%; height: 100%;
            padding: 10%;
            display: flex;
            flex-direction: column;
            justify-content: center;
            opacity: 0;
            visibility: hidden;
            transition: opacity 0.5s ease, transform 0.5s ease;
            transform: scale(0.95);
        }

        .slide.active {
            opacity: 1;
            visibility: visible;
            transform: scale(1);
            z-index: 10;
        }

        /* Typography */
        h1 { font-size: 4rem; font-weight: 900; margin-bottom: 1rem; line-height: 1.1; }
        h2 { font-size: 2rem; font-weight: 300; color: var(--text-muted); margin-bottom: 2rem; }
        p { font-size: 1.2rem; line-height: 1.6; margin-bottom: 1rem; color: #D1D5DB; }
        .accent { color: var(--accent-cyan); }
        .accent-red { color: var(--accent-coral); }

        /* Grids & Layouts */
        .grid-3 {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 2rem;
            margin-top: 2rem;
        }
        .card {
            background: var(--panel-bg);
            padding: 2rem;
            border-radius: 12px;
            border-top: 4px solid var(--accent-cyan);
        }
        .card h3 { font-size: 1.5rem; margin-bottom: 1rem; color: var(--text-main); }
        .icon { font-size: 3rem; margin-bottom: 1rem; display: block; }

        /* 2x2 Matrix */
        .matrix {
            display: grid;
            grid-template-columns: 1fr 1fr;
            grid-template-rows: 1fr 1fr;
            gap: 10px;
            width: 80%;
            margin: 0 auto;
            height: 50vh;
        }
        .matrix-cell {
            background: var(--panel-bg);
            border-radius: 8px;
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            text-align: center;
            padding: 2rem;
            border: 1px solid rgba(255,255,255,0.1);
        }
        .matrix-cell.winner {
            background: rgba(0, 229, 255, 0.1);
            border-color: var(--accent-cyan);
            box-shadow: 0 0 20px rgba(0, 229, 255, 0.2);
        }

        /* Navigation Controls */
        #controls {
            position: fixed;
            bottom: 30px;
            left: 0; right: 0;
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 0 50px;
            z-index: 100;
        }
        button {
            background: transparent;
            color: var(--text-main);
            border: 1px solid var(--text-muted);
            padding: 10px 20px;
            border-radius: 30px;
            font-size: 1rem;
            cursor: pointer;
            transition: all 0.2s;
            font-family: 'Inter', sans-serif;
        }
        button:hover { background: var(--text-main); color: var(--bg-color); }
        .nav-btn:disabled { opacity: 0.3; cursor: not-allowed; pointer-events: none; }

        #progress-bar {
            position: fixed;
            top: 0; left: 0;
            height: 4px;
            background: var(--accent-cyan);
            width: 10%;
            transition: width 0.3s ease;
            z-index: 100;
        }

        /* Speaker Notes */
        #notes-panel {
            position: fixed;
            bottom: 80px;
            left: 50%;
            transform: translateX(-50%);
            width: 60%;
            background: #1A2642;
            padding: 20px;
            border-radius: 12px;
            border-left: 5px solid var(--accent-coral);
            display: none;
            z-index: 90;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            font-size: 1.1rem;
        }
        #notes-panel.visible { display: block; }
        .notes-label { font-size: 0.8rem; text-transform: uppercase; color: var(--accent-coral); margin-bottom: 5px; font-weight: bold; }
    </style>
</head>
